# ──────────────────────────────────────────────────────────────────
# PUBLIC — download certificate as PDF
# ──────────────────────────────────────────────────────────────────

@api_view(["GET"])
@permission_classes([AllowAny])
def download_certificate(request, uuid):
    """
    GET /api/certificates/<uuid>/download/
    Returns the certificate as a downloadable PDF.
    AllowAny — link is unguessable (UUID). FR-VOL3, FR-A6.
    """
    try:
        cert = Certificate.objects.select_related("user", "event").get(uuid=uuid)
    except Certificate.DoesNotExist:
        return Response({"error": "Certificate not found."}, status=status.HTTP_404_NOT_FOUND)

    if cert.status == "revoked":
        return Response({"error": "This certificate has been revoked."}, status=status.HTTP_410_GONE)
    

@api_view(["GET"])
@permission_classes([AllowAny])
def view_certificate(request, uuid):
    """
    GET /api/certificates/<uuid>/view/
    Returns PDF inline for browser preview (no download prompt).
    """
    try:
        cert = Certificate.objects.select_related("user", "event").get(uuid=uuid)
    except Certificate.DoesNotExist:
        return Response({"error": "Certificate not found."}, status=status.HTTP_404_NOT_FOUND)

    if cert.status == "revoked":
        return Response({"error": "This certificate has been revoked."}, status=status.HTTP_410_GONE)

    try:
        from weasyprint import HTML as WeasyprintHTML
        html_str = _build_certificate_html(
            name        = cert.user.full_name,
            event_name  = cert.event.title,
            date        = cert.issued_at.strftime("%B %d, %Y"),
            owner_name  = "Zena Abu Gaith",
            owner_title = "OWNER OF MENA",
        )
        pdf_bytes = WeasyprintHTML(string=html_str).write_pdf()
    except Exception as e:
        return Response({"error": f"Failed to generate certificate: {str(e)}"}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    response = HttpResponse(pdf_bytes, content_type="application/pdf")
    response["Content-Disposition"] = "inline"
    return response

    # Build dynamic data
    volunteer_name = cert.user.full_name
    event_name     = cert.event.title
    event_date     = cert.issued_at.strftime("%B %d, %Y")

    # Generate HTML and convert to PDF
    try:
        from weasyprint import HTML as WeasyprintHTML
        html_str = _build_certificate_html(
            name        = volunteer_name,
            event_name  = event_name,
            date        = event_date,
            owner_name  = "Zena Abu Gaith",
            owner_title = "OWNER OF MENA",
        )
        pdf_bytes = WeasyprintHTML(string=html_str).write_pdf()
    except Exception as e:
        return Response(
            {"error": f"Failed to generate certificate: {str(e)}"},
            status=status.HTTP_500_INTERNAL_SERVER_ERROR
        )

    # Build a clean filename
    safe_name  = volunteer_name.replace(" ", "_")
    safe_event = event_name.replace(" ", "_")[:30]
    filename   = f"MENA_Certificate_{safe_name}_{safe_event}.pdf"

    response = HttpResponse(pdf_bytes, content_type="application/pdf")
    response["Content-Disposition"] = f'attachment; filename="{filename}"' 
    return response


# ──────────────────────────────────────────────────────────────────
# USER — list own certificates
# ──────────────────────────────────────────────────────────────────

@api_view(["GET"])
@permission_classes([IsAuthenticated])
def my_certificates(request):
    """GET /api/certificates/"""
    certs = Certificate.objects.filter(user=request.user, status="issued").select_related("event")
    return Response(CertificateSerializer(certs, many=True).data)


# ──────────────────────────────────────────────────────────────────
# ADMIN
# ──────────────────────────────────────────────────────────────────

@api_view(["GET"])
@permission_classes([IsAdmin])
def admin_list_certificates(request):
    """GET /api/certificates/admin/"""
    qs = Certificate.objects.select_related("user", "event", "issued_by").all()
    s = request.query_params.get("status")
    if s:
        qs = qs.filter(status=s)
    return Response({
        "count":   qs.count(),
        "results": AdminCertificateSerializer(qs, many=True).data,
    })


@api_view(["POST"])
@permission_classes([IsAdmin])
def admin_issue_certificate(request):
    """
    POST /api/certificates/admin/issue/
    Body: { user_id, event_id }
    """
    user_id  = request.data.get("user_id")
    event_id = request.data.get("event_id")
    if not user_id or not event_id:
        return Response({"error": "user_id and event_id are required."}, status=status.HTTP_400_BAD_REQUEST)

    from django.contrib.auth import get_user_model
    from apps.events.models import Event
    User = get_user_model()

    try:
        user  = User.objects.get(id=user_id)
        event = Event.objects.get(id=event_id)
    except (User.DoesNotExist, Event.DoesNotExist):
        return Response({"error": "User or event not found."}, status=status.HTTP_404_NOT_FOUND)

    try:
        user  = User.objects.get(id=user_id)
        event = Event.objects.get(id=event_id)
    except (User.DoesNotExist, Event.DoesNotExist):
        return Response({"error": "User or event not found."}, status=status.HTTP_404_NOT_FOUND)

    result = issue_certificate(user=user, event=event, issued_by=request.user)
    cert = result[0] if isinstance(result, tuple) else result
    return Response({
        "message":     f"Certificate issued to {user.full_name}.",
        "certificate": AdminCertificateSerializer(cert).data,
    }, status=status.HTTP_201_CREATED)


@api_view(["POST"])
@permission_classes([IsAdmin])
def admin_issue_bulk(request):
    """
    POST /api/certificates/admin/issue-bulk/
    Body: { event_id }
    Issues certificates to all approved applicants for the event.
    """
    event_id = request.data.get("event_id")
    if not event_id:
        return Response({"error": "event_id is required."}, status=status.HTTP_400_BAD_REQUEST)

    from apps.events.models import Event
    try:
        event = Event.objects.get(id=event_id)
    except Event.DoesNotExist:
        return Response({"error": "Event not found."}, status=status.HTTP_404_NOT_FOUND)

    issued, skipped = issue_certificates_for_event(event=event, issued_by=request.user)
    return Response({
        "message": f"Issued {issued} certificate(s). {skipped} already existed.",
        "issued":  issued,
        "skipped": skipped,
    })


@api_view(["POST"])
@permission_classes([IsAdmin])
def admin_revoke_certificate(request, cert_id):
    """POST /api/certificates/admin/<id>/revoke/"""
    try:
        cert = Certificate.objects.select_related("user").get(id=cert_id)
    except Certificate.DoesNotExist:
        return Response({"error": "Certificate not found."}, status=status.HTTP_404_NOT_FOUND)

    revoke_certificate(cert)
    return Response({"message": f"Certificate for {cert.user.full_name} has been revoked."})